INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0f40d060-11c0-4590-8f8a-f60b8a7e06d7',
  '00000000-0000-0000-0000-000000000001',
  $escape$Building Ethereum Accounts and Transactions on Base$escape$,
  $escape$Base provides a robust set of APIs for interacting with the Ethereum blockchain. To create an Ethereum account on Base, you can use the `eth_account` module. This module allows you to generate new accounts, sign transactions, and verify signatures. When building transactions, you'll need to specify the `from` address, `to` address, `value`, `gas`, and `gasPrice`. The `eth_transaction` module on Base handles the low-level details of transaction construction. Post-merge, Ethereum has transitioned to a Proof of Stake (PoS) consensus algorithm, which is supported by Base's `eth_consensus` module.$escape$,
  $escape$const { eth_account, eth_transaction, eth_consensus } = require('base');
const account = eth_account.create();
const tx = eth_transaction.create({ from: account.address, to: '0x...', value: '1 ether' });
eth_consensus.stake(account, '100 ether');$escape$,
  $escape$javascript$escape$,
