INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'db0c4bb2-cb31-4995-a26f-a0e6de57e545',
  '00000000-0000-0000-0000-000000000001',
  $escape$BASE Transaction Lifecycle — Mempool, Ordering, Finality, Reorg Risk$escape$,
  $escape$BASE transactions are processed through a mempool, which is a collection of unconfirmed transactions awaiting inclusion in a block. When a validator proposes a new block, it selects transactions from the mempool based on their priority (gas price and gas limit). The block is then broadcast to the network, and validators verify its transactions. Once a block is finalized, its transactions are considered irreversible. However, if a reorg occurs (a new block is added to the chain that invalidates previous blocks), unconfirmed transactions in the mempool may need to be re-propagated.$escape$,
  NULL,
  NULL,
